+            "r_f_s: java.util.function.@Test.TypeAnno Supplier<java.lang.String>",
+            "()->\"r_f_s\": java.util.function.@Test.TypeAnno Supplier<java.lang.String>",
+            "r_init_i: java.util.function.@Test.TypeAnno Supplier<java.lang.String>",
+            "()->\"r_init_i\": java.util.function.@Test.TypeAnno Supplier<java.lang.String>",
