+            "()->\"r_m_i\": java.util.function.@Test.TypeAnno Supplier<java.lang.String>",
+            "r_g_s: java.util.function.@Test.TypeAnno Supplier<java.lang.String>",
+            "()->\"r_g_s\": java.util.function.@Test.TypeAnno Supplier<java.lang.String>",
+            "()->\"t_cr\": java.util.function.@Test.TypeAnno Supplier<java.lang.String>",
